        try:
            unit_index = int(ln.split(":",1)[1].strip())
        except:
            pass
        break

# helper to extract 9 lines after a header
def extract_block(header):
    for i, ln in enumerate(lines):
        if ln.strip() == header:
            block = []
            for j in range(i+1, i+1+9):
                if j < len(lines):
                    block.append(lines[j].strip())
            return block
    return None

orig = extract_block("ORIGINAL_PUZZLE:")
sol = extract_block("SOLUTION_PUZZLE:")

# basic validations
if unit_index is None or orig is None or sol is None or len(orig)!=9 or len(sol)!=9:
    issue = "context parse error"
    result = {"index": unit_index if unit_index is not None else 0, "ok": False, "issue": issue}
    done(result)

# parse into digits
orig_rows = orig
sol_rows = sol

# verify rows are 9 chars and digits
for r in orig_rows + sol_rows:
    if len(r) != 9 or not all(ch.isdigit() for ch in r):
        result = {"index": unit_index, "ok": False, "issue": "invalid puzzle rows"}
        done(result)

# check column
col = unit_index
mismatches = []
col_digits = []
for row_idx in range(9):
    o = orig_rows[row_idx][col]
    s = sol_rows[row_idx][col]
    col_digits.append(s)
    if o != '0' and o != s:
        mismatches.append(f"row{row_idx} expected{o} got{s}")

# verify digits 1-9 exactly once
from collections import Counter
cnt = Counter(col_digits)
# should be digits '1'..'9' each once
expected = [str(i) for i in range(1,10)]
missing = [d for d in expected if cnt[d]==0]
duplicates = [d for d,c in cnt.items() if c>1]

if mismatches:
    issue = mismatches[0]  # concise: first mismatch
    result = {"index": unit_index, "ok": False, "issue": issue}
    done(result)

if missing or duplicates:
    parts = []
    if missing:
        parts.append("missing:"+",".join(missing))
    if duplicates:
        parts.append("duplicates:"+",".join(duplicates))
    issue = ";".join(parts)
    result = {"index": unit_index, "ok": False, "issue": issue}
    done(result)

# all good
result = {"index": unit_index, "ok": True, "issue": ""}
done(result)
